from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    from collections import defaultdict

    # Group triples by subject
    subj_map = defaultdict(list)
    for t in triples:
        subj_map[t.subject].append((t.predicate, t.object))

    # Helper to render a single predicate‑object pair
    def render(p: str, o: str) -> str:
        if p in ("birthDate", "birthYear"):
            return f"was born in {o}"
        if p == "deathDate":
            return f"died on {o}"
        if p == "deathPlace":
            return f"died in {o}"
        if p == "birthPlace":
            return f"was born in {o}"
        if p == "origin":
            return f"originated from {o}"
        if p == "genre":
            return f"plays {o} music"
        if p == "instrument":
            return f"plays the {o}"
        if p == "occupation":
            return f"works as a {o}"
        if p == "nationality":
            return f"is from {o}"
        if p == "associatedBand/associatedMusicalArtist":
            return f"plays with {o}"
        if p == "recordLabel":
            return f"is signed to {o}"
        if p == "background":
            return f"has a background as {o}"
        if p == "activeYearsStartYear":
            return f"started activity in {o}"
        if p == "activeYearsEndYear":
            return f"ended activity in {o}"
        if p == "capital":
            return f"has capital {o}"
        if p == "leader":
            return f"{o} is the leader"
        if p == "leaderTitle":
            return f"the leader holds the title {o}"
        if p == "country":
            return f"is part of {o}"
        # default fallback
        return f"{p} {o}"

    # Predicates that link to another subject
    linking_preds = {"nationality", "origin", "country", "isPartOf"}

    sentences = []
    for subj, props in subj_map.items():
        # Collect values per predicate
        assoc = []
        genres = []
        instruments = []
        occupations = []
        background = None
        birth = None
        death = None
        active_start = None
        active_end = None
        nationality = None
        origin = None
        country = None
        extra_clauses = []

        for p, o in props:
            if p == "associatedBand/associatedMusicalArtist":
                assoc.append(o)
            elif p == "genre":
                genres.append(o)
            elif p == "instrument":
                instruments.append(o)
            elif p == "occupation":
                occupations.append(o)
            elif p == "background":
                background = o
            elif p in ("birthDate", "birthYear"):
                birth = o
            elif p in ("deathDate", "deathPlace"):
                death = (p, o)
            elif p == "activeYearsStartYear":
                active_start = o
            elif p == "activeYearsEndYear":
                active_end = o
            elif p == "nationality":
                nationality = o
            elif p == "origin":
                origin = o
            elif p == "country":
                country = o
            else:
                extra_clauses.append(render(p, o))

        parts = [subj]

        if occupations:
            parts.append("is a " + " and ".join(occupations))
        if background:
            parts.append(f"with a background as {background}")
        if instruments:
            parts.append("who plays " + " and ".join(instruments))
        if genres:
            parts.append("and performs " + " and ".join(genres) + " music")
        if assoc:
            if len(assoc) == 1:
                band_str = assoc[0]
            else:
                band_str = ", ".join(assoc[:-1]) + " and " + assoc[-1]
            parts.append(f"who has performed with the bands {band_str}")
        if active_start or active_end:
            if active_start and active_end:
                parts.append(f"active from {active_start} to {active_end}")
            elif active_start:
                parts.append(f"active since {active_start}")
            else:
                parts.append(f"active until {active_end}")
        if birth:
            parts.append(f"born in {birth}")
        if death:
            dp, dobj = death
            if dp == "deathDate":
                parts.append(f"died on {dobj}")
            else:
                parts.append(f"died in {dobj}")
        if nationality:
            parts.append(f"from {nationality}")
        elif origin:
            parts.append(f"originated from {origin}")
        elif country:
            parts.append(f"from {country}")

        parts.extend(extra_clauses)

        sentence = " ".join(parts).strip() + "."
        sentences.append(sentence)

    return " ".join(sentences)

# EVOLVE-BLOCK-END

